+    let cx = &pair.cx;
+
+    // Open multiple streams with pending data.
+    let s0 = pair.client.open_local_bidi(cx).expect("open s0");
+    let s1 = pair.client.open_local_bidi(cx).expect("open s1");
+    let s2 = pair.client.open_local_bidi(cx).expect("open s2");
