+    // Now s1 (4) is also rejected.
+    let err = client_h3
+        .on_request_stream_frame(s1.0, &H3Frame::Headers(vec![0x84]))
+        .expect_err("s1 should now be rejected");
+    assert_eq!(
+        err,
+        H3NativeError::ControlProtocol("request stream id rejected after GOAWAY")
