+/// Convenience: build a SentPacketMeta for direct QuicTransportMachine use.
+fn sent(space: PacketNumberSpace, pn: u64, bytes: u64, t: u64) -> SentPacketMeta {
+    SentPacketMeta {
+        space,
+        packet_number: pn,
+        bytes,
+        ack_eliciting: true,
+        in_flight: true,
+        time_sent_micros: t,
+    }
+}
